<?php
 declare(strict_types=1); namespace tapmeppe\composer\helpers; abstract class Summon extends \Illuminate\Console\Command { protected string $description; protected final function getParameters(array $arguments, array $options = []): array { $parameters = []; foreach ($arguments as $argument) $parameters[$argument] = $this->argument($argument); foreach ($options as $option) if ($value = $this->option($option)) $parameters[$option] = $value; return $parameters; } protected final function runSeeder(callable $success, callable $failure, string $seeder, array $arguments, array $options = []): void { $this->runSeederWithParameters($success, $failure, $seeder, $this->getParameters($arguments, $options)); } protected final function runSeederAdministrator(string $seeder, array $arguments, array $options = []): void { $this->runSeeder( fn(object $parameters) => "Administrator '$parameters->email' has been created.", fn(object $parameters) => "Administrator '$parameters->email' could not be created.", $seeder, $arguments, $options ); } protected final function runSeederWithParameters(callable $success, callable $failure, string $seeder, array $parameters): void { $this->info($this->description); if (app($seeder)->run($parameters)) $this->info('🟢 ' . $success((object) $parameters)); else $this->info('🔴 ' . $failure((object) $parameters)); } } 